-- Meeting: Tristan Pelligrino and Barb Willans (2025-11-07 19:00:00+00)
WITH new_meeting AS (
  INSERT INTO compass_meetings (contract_id, meeting_date, source, external_id, title, participants, duration_seconds, recording_url, transcript, sentiment, raw_metadata, created_at, updated_at)
  VALUES (
    '52b3ee0f-cbad-4031-a387-79ecb54874fb',
    '2025-11-07 19:00:00+00',
    'fireflies',
    '01K8Y5Z3H8VP7G6DH216RN9PQR',
    'Tristan Pelligrino and Barb Willans',
    '{"Tristan Pelligrino","Maria","Tristan Pelligrino","Justin","Kyle Scoville","bwillans"}'::text[],
