me":771.73,"speaker_name":"Gab"},{"text":"I didn''t, I didn''t come up with it.","index":230,"end_time":775.37,"speaker_id":0,"start_time":773.49,"speaker_name":"Tim"},{"text":"It was Gab, actually.","index":231,"end_time":777.33,"speaker_id":0,"start_time":775.37,"speaker_name":"Tim"},{"text":"It was either Gab or Gabriella.","index":232,"end_time":780.33,"speaker_id":0,"start_time":778.69,"speaker_name":"Tim"},{"text":"I don''t know who was who did it.","index":233,"end_time":781.89,"speaker_id":0,"start_time":780.33,"speaker_name":"Tim"},{"text":"One of those two?","index":234,"end_time":783.09,"speaker_id":0,"start_time":782.29,"speaker_name":"Tim"},{"text":"One of them.","index":235,"end_time":783.69,"speaker_id":1,"start_time":783.09,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":236,"end_time":784.13,"speaker_id":0,"start_time":783.69,"speaker_name":"Tim"},{"text":"Yeah.","index":237,"end_time":784.69,"speaker_id":1,"start_time":784.21,"speaker_name":"Baylee Gunnell"},{"text":"Cool.","index":238,"end_time":786.78,"speaker_id":1,"start_time":786.46,"speaker_name":"Baylee Gunnell"},{"text":"No, that''s exciting.","index":239,"end_time":787.98,"speaker_id":2,"start_time":786.94,"speaker_name":"Gab"},{"text":"And then once we have the guest promo assets, I''m also going to come over top of Tim''s email to guests and be like, hey, it''s launch day.","index":240,"end_time":798.46,"speaker_id":2,"start_time":789.66,"speaker_name":"Gab"},{"text":"Happy to have you in this.","index":241,"end_time":800.06,"speaker_id":2,"start_time":798.78,"speaker_name":"Gab"},{"text":"Here are your assets.","index":242,"end_time":801.82,"speaker_id":2,"start_time":800.54,"speaker_name":"Gab"},{"text":"Here''s a partner marketing guide.","index":243,"end_time":803.5,"speaker_id":2,"start_time":801.82,"speaker_name":"Gab"},{"text":"Have a great day.","index":244,"end_time":806.14,"speaker_id":2,"start_time":804.62,"speaker_name":"Gab"},{"text":"Yes, it''s going to be great.","index":245,"end_time":808.54,"speaker_id":2,"start_time":807.02,"speaker_name":"Gab"},{"text":"So excited.","index":246,"end_time":809.42,"speaker_id":2,"start_time":808.62,"speaker_name":"Gab"},{"text":"So when I send that out, Gab, I''ll do that.","index":247,"end_time":812.38,"speaker_id":0,"start_time":810.3,"speaker_name":"Tim"},{"text":"I''ll try to do it Monday morning or whenever Bailey gets me the.","index":248,"end_time":815.38,"speaker_id":0,"start_time":812.38,"speaker_name":"Tim"},{"text":"Okay, I''ll CC you on all emails.","index":249,"end_time":817.88,"speaker_id":0,"start_time":815.38,"speaker_name":"Tim"},{"text":"And then I like that a couple days later you come on top of it.","index":250,"end_time":821.12,"speaker_id":0,"start_time":817.88,"speaker_name":"Tim"},{"text":"Hey, it''s launch day.","index":251,"end_time":822.12,"speaker_id":0,"start_time":821.12,"speaker_name":"Tim"},{"text":"We''re so excited.","index":252,"end_time":823.2,"speaker_id":0,"start_time":822.28,"speaker_name":"Tim"},{"text":"Thank you.","index":253,"end_time":823.8,"speaker_id":0,"start_time":823.2,"speaker_name":"Tim"},{"text":"Here''s.","index":254,"end_time":824.44,"speaker_id":0,"start_time":823.96,"speaker_name":"Tim"},{"text":"And even in your email, complimentary, complimentary social package or whatever.","index":255,"end_time":829.8,"speaker_id":0,"start_time":824.44,"speaker_name":"Tim"},{"text":"Yeah.","index":256,"end_time":830.4,"speaker_id":2,"start_time":829.96,"speaker_name":"Gab"},{"text":"Oh, that''s really nice way to put it.","index":257,"end_time":832.16,"speaker_id":2,"start_time":830.4,"speaker_name":"Gab"},{"text":"You can, if you and your individual emails to guests could just say, like, anticipate an email from Gab in the next couple days to help this thing and that would be great.","index":258,"end_time":844.15,"speaker_id":2,"start_time":832.16,"speaker_name":"Gab"},{"text":"Cool.","index":259,"end_time":846.71,"speaker_id":2,"start_time":846.23,"speaker_name":"Gab"},{"text":"Okay.","index":260,"end_time":848.55,"speaker_id":2,"start_time":847.91,"speaker_name":"Gab"},{"text":"Okay.","index":261,"end_time":852.11,"speaker_id":1,"start_time":851.59,"speaker_name":"Baylee Gunnell"},{"text":"Just taking a look.","index":262,"end_time":853.11,"speaker_id":1,"start_time":852.11,"speaker_name":"Baylee Gunnell"},{"text":"Oh, actually, yeah, no, they''re good.","index":263,"end_time":858.51,"speaker_id":1,"start_time":855.19,"speaker_name":"Baylee Gunnell"},{"text":"I''m just.","index":264,"end_time":859.11,"speaker_id":1,"start_time":858.51,"speaker_name":"Baylee Gunnell"},{"text":"We''ve been having a lot of back and forth conversations internally because there''s a lot going on.","index":265,"end_time":864.23,"speaker_id":1,"start_time":859.75,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, they''re good.","index":266,"end_time":865.75,"speaker_id":1,"start_time":864.79,"speaker_name":"Baylee Gunnell"},{"text":"They''re good.","index":267,"end_time":866.51,"speaker_id":1,"start_time":865.91,"speaker_name":"Baylee Gunnell"},{"text":"I''ll take a final look at them and send it over to you.","index":268,"end_time":869.03,"speaker_id":1,"start_time":866.51,"speaker_name":"Baylee Gunnell"},{"text":"Okay.","index":269,"end_time":869.63,"speaker_id":1,"start_time":869.03,"speaker_name":"Baylee Gunnell"},{"text":"Hey, Bailey.","index":270,"end_time":872.27,"speaker_id":0,"start_time":871.31,"speaker_name":"Tim"},{"text":"Yes.","index":271,"end_time":873.15,"speaker_id":1,"start_time":872.67,"speaker_name":"Baylee Gunnell"},{"text":"Do you, do you want.","index":272,"end_time":874.75,"speaker_id":0,"start_time":873.31,"speaker_name":"Tim"},{"text":"No, you should do.","index":273,"end_time":875.95,"speaker_id":0,"start_time":874.91,"speaker_name":"Tim"},{"text":"You should try to.","index":274,"end_time":877.79,"speaker_id":0,"start_time":876.91,"speaker_name":"Tim"},{"text":"You should try to get a raise.","index":275,"end_time":879.07,"speaker_id":0,"start_time":877.79,"speaker_name":"Tim"},{"text":"And, and we can suggest that we''re gonna, we''re gonna fire you guys if you don''t get a raise or at least can you send something that we can recommend how great or, and say how great you have been through this.","index":276,"end_time":894.67,"speaker_id":0,"start_time":879.23,"speaker_name":"Tim"},{"text":"You''re one of the top people from a vendor standpoint that I''ve ever been around.","index":277,"end_time":900.37,"speaker_id":0,"start_time":895.09,"speaker_name":"Tim"},{"text":"Wow.","index":278,"end_time":902.13,"speaker_id":1,"start_time":901.65,"speaker_name":"Baylee Gunnell"},{"text":"Because one thing you don''t, you don''t like.","index":279,"end_time":907.85,"speaker_id":0,"start_time":903.33,"speaker_name":"Tim"},{"text":"I try to take us off to tangents and you get us back on.","index":280,"end_time":911.01,"speaker_id":0,"start_time":907.85,"speaker_name":"Tim"},{"text":"Right.","index":281,"end_time":913.05,"speaker_id":1,"start_time":912.69,"speaker_name":"Baylee Gunnell"},{"text":"Gab, doesn''t she.","index":282,"end_time":914.13,"speaker_id":0,"start_time":913.05,"speaker_name":"Tim"},{"text":"He''s like, it''s needed.","index":283,"end_time":915.93,"speaker_id":1,"start_time":914.29,"speaker_name":"Baylee Gunnell"},{"text":"He''s like, it''s needed.","index":284,"end_time":917.25,"speaker_id":1,"start_time":915.93,"speaker_name":"Baylee Gunnell"},{"text":"She''s like, ignore.","index":285,"end_time":918.93,"speaker_id":0,"start_time":917.41,"speaker_name":"Tim"},{"text":"Let''s get it back.","index":286,"end_time":919.81,"speaker_id":0,"start_time":919.01,"speaker_name":"Tim"},{"text":"All right.","index":287,"end_time":920.21,"speaker_id":0,"start_time":919.81,"speaker_name":"Tim"},{"text":"I''m always happy to hype up Bailey on any platform, so just let us know if we can drop, like, a review.","index":288,"end_time":929.15,"speaker_id":2,"start_time":922.67,"speaker_name":"Gab"},{"text":"I might do.","index":289,"end_time":929.95,"speaker_id":0,"start_time":929.31,"speaker_name":"Tim"},{"text":"Yeah.","index":290,"end_time":930.79,"speaker_id":1,"start_time":930.43,"speaker_name":"Baylee Gunnell"},{"text":"I''m gonna do a LinkedIn recommendation to you right now.","index":291,"end_time":933.23,"speaker_id":0,"start_time":930.79,"speaker_name":"Tim"},{"text":"Wow.","index":292,"end_time":934.31,"speaker_id":2,"start_time":933.87,"speaker_name":"Gab"},{"text":"Actually, you are the best.","index":293,"end_time":936.47,"speaker_id":1,"start_time":934.31,"speaker_name":"Baylee Gunnell"},{"text":"I love working with you all.","index":294,"end_time":937.95,"speaker_id":1,"start_time":936.47,"speaker_name":"Baylee Gunnell"},{"text":"This makes me feel really good.","index":295,"end_time":939.87,"speaker_id":1,"start_time":938.51,"speaker_name":"Baylee Gunnell"},{"text":"Good.","index":296,"end_time":941.23,"speaker_id":2,"start_time":940.83,"speaker_name":"Gab"},{"text":"Can I.","index":297,"end_time":941.87,"speaker_id":0,"start_time":941.39,"speaker_name":"Tim"},{"text":"Can I tell you guys a quick story?","index":298,"end_time":943.31,"speaker_id":0,"start_time":941.87,"speaker_name":"Tim"},{"text":"Tim, hold on.","index":299,"end_time":945.71,"speaker_id":2,"start_time":944.19,"speaker_name":"Gab"},{"text":"It''ll take one minute.","index":300,"end_time":948.43,"speaker_id":0,"start_time":947.39,"speaker_name":"Tim"},{"text":"It''ll take one.","index":301,"end_time":949.15,"speaker_id":0,"start_time":948.43,"speaker_name":"Tim"},{"text":"One minute.","index":302,"end_time":950.03,"speaker_id":0,"start_time":949.39,"speaker_name":"Tim"},{"text":"One minute.","index":303,"end_time":950.72,"speaker_id":0,"start_time":950.24,"speaker_name":"Tim"},{"text":"I was in Charlotte.","index":304,"end_time":951.76,"speaker_id":0,"start_time":950.88,"speaker_name":"Tim"},{"text":"I was at Charlotte, North Carolina, and I''m having dinner alone and I''m waiting to take to go.","index":305,"end_time":957.32,"speaker_id":0,"start_time":951.76,"speaker_name":"Tim"},{"text":"A woman comes up to me and she''s going to the bathroom.","index":306,"end_time":960.64,"speaker_id":0,"start_time":957.32,"speaker_name":"Tim"},{"text":"She''s like, hey, Mr. Bald Man.","index":307,"end_time":962.16,"speaker_id":0,"start_time":960.64,"speaker_name":"Tim"},{"text":"And she goes to the bathroom.","index":308,"end_time":963.52,"speaker_id":0,"start_time":962.16,"speaker_name":"Tim"},{"text":"And I''m like, oh, my gosh, I feel so down about my Mr. Baldman.","index":309,"end_time":967.2,"speaker_id":0,"start_time":963.52,"speaker_name":"Tim"},{"text":"Then she.","index":310,"end_time":967.68,"speaker_id":0,"start_time":967.2,"speaker_name":"Tim"},{"text":"Then she comes back and goes, I hope you didn''t think that was.","index":311,"end_time":972.24,"speaker_id":0,"start_time":968.24,"speaker_name":"Tim"},{"text":"I was making fun of you.","index":312,"end_time":973.68,"speaker_id":0,"start_time":972.4,"speaker_name":"Tim"},{"text":"I love bald men and you are extremely handsome.","index":313,"end_time":976.16,"speaker_id":0,"start_time":973.68,"speaker_name":"Tim"},{"text":"And then she walks away.","index":314,"end_time":977.42,"speaker_id":0,"start_time":976.38,"speaker_name":"Tim"},{"text":"I''m like, I went from being down to being way up here.","index":315,"end_time":981.74,"speaker_id":0,"start_time":977.42,"speaker_name":"Tim"},{"text":"So that''s it.","index":316,"end_time":982.46,"speaker_id":0,"start_time":981.74,"speaker_name":"Tim"},{"text":"We''re so back.","index":317,"end_time":983.74,"speaker_id":2,"start_time":982.78,"speaker_name":"Gab"},{"text":"It''s so over.","index":318,"end_time":985.26,"speaker_id":2,"start_time":984.38,"speaker_name":"Gab"},{"text":"We''re so back.","index":319,"end_time":986.54,"speaker_id":2,"start_time":985.42,"speaker_name":"Gab"},{"text":"Yeah.","index":320,"end_time":987.5,"speaker_id":2,"start_time":987.02,"speaker_name":"Gab"},{"text":"Amazing.","index":321,"end_time":990.62,"speaker_id":2,"start_time":989.9,"speaker_name":"Gab"},{"text":"No, I love.","index":322,"end_time":991.54,"speaker_id":1,"start_time":990.86,"speaker_name":"Baylee Gunnell"},{"text":"I thought she gotta come back and tell you that.","index":323,"end_time":993.82,"speaker_id":1,"start_time":991.54,"speaker_name":"Baylee Gunnell"},{"text":"Love.","index":324,"end_time":997.02,"speaker_id":0,"start_time":996.62,"speaker_name":"Tim"},{"text":"I love.","index":325,"end_time":997.58,"speaker_id":0,"start_time":997.02,"speaker_name":"Tim"},{"text":"My first comment on this slide, Bailey, is that Ryan loves the.","index":326,"end_time":1001.82,"speaker_id":2,"start_time":998.3,"speaker_name":"Gab"},{"text":"The GIFs and how they came out.","index":327,"end_time":1003.7,"speaker_id":2,"start_time":1001.98,"speaker_name":"Gab"},{"text":"Like, I. Oh, good.","index":328,"end_time":1004.86,"speaker_id":2,"start_time":1003.7,"speaker_name":"Gab"},{"text":"And Ryan, like, he gives good feedback, but I feel like I rare ever get the, like, I love these from.","index":329,"end_time":1010.76,"speaker_id":2,"start_time":1004.86,"speaker_name":"Gab"},{"text":"From Ryan, so that felt good.","index":330,"end_time":1012.84,"speaker_id":2,"start_time":1010.76,"speaker_name":"Gab"},{"text":"But these are great.","index":331,"end_time":1015,"speaker_id":2,"start_time":1014.04,"speaker_name":"Gab"},{"text":"I already scheduled them out over the next two weeks and got our, like, employee advocacy system up to date so that people can share them from within the org.","index":332,"end_time":1026.6,"speaker_id":2,"start_time":1015,"speaker_name":"Gab"},{"text":"So job well done.","index":333,"end_time":1028.52,"speaker_id":2,"start_time":1026.68,"speaker_name":"Gab"},{"text":"Kudos.","index":334,"end_time":1029.48,"speaker_id":2,"start_time":1028.84,"speaker_name":"Gab"},{"text":"Great.","index":335,"end_time":1029.88,"speaker_id":1,"start_time":1029.48,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, I''m glad You like these GIFs.","index":336,"end_time":1032.6,"speaker_id":1,"start_time":1030.12,"speaker_name":"Baylee Gunnell"},{"text":"I think they''re so fun.","index":337,"end_time":1033.96,"speaker_id":1,"start_time":1032.6,"speaker_name":"Baylee Gunnell"},{"text":"And I''ve actually started doing them for more clients because we''ve done so many.","index":338,"end_time":1038.11,"speaker_id":1,"start_time":1034.55,"speaker_name":"Baylee Gunnell"},{"text":"Like, everyone needs these.","index":339,"end_time":1039.91,"speaker_id":1,"start_time":1038.11,"speaker_name":"Baylee Gunnell"},{"text":"They''re great.","index":340,"end_time":1040.79,"speaker_id":1,"start_time":1039.99,"speaker_name":"Baylee Gunnell"},{"text":"Different way to, like, talk about a product or an enhancement.","index":341,"end_time":1045.27,"speaker_id":2,"start_time":1041.67,"speaker_name":"Gab"},{"text":"Can you show it?","index":342,"end_time":1046.95,"speaker_id":0,"start_time":1045.91,"speaker_name":"Tim"},{"text":"I can send them to you, Tim.","index":343,"end_time":1049.75,"speaker_id":2,"start_time":1048.31,"speaker_name":"Gab"},{"text":"Thank you.","index":344,"end_time":1051.19,"speaker_id":0,"start_time":1050.63,"speaker_name":"Tim"},{"text":"Yeah, we can just look and show you really quick.","index":345,"end_time":1055.51,"speaker_id":1,"start_time":1051.67,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, they look really good.","index":346,"end_time":1057.43,"speaker_id":1,"start_time":1055.99,"speaker_name":"Baylee Gunnell"},{"text":"I think that''s sped up, but like, the.","index":347,"end_time":1064.16,"speaker_id":2,"start_time":1062,"speaker_name":"Gab"},{"text":"You can.","index":348,"end_time":1064.8,"speaker_id":1,"start_time":1064.24,"speaker_name":"Baylee Gunnell"},{"text":"Like the version.","index":349,"end_time":1065.76,"speaker_id":2,"start_time":1064.8,"speaker_name":"Gab"},{"text":"You can slow it down.","index":350,"end_time":1067.2,"speaker_id":2,"start_time":1066.16,"speaker_name":"Gab"},{"text":"Yeah, sorry, I. I watch everything super fast.","index":351,"end_time":1070.8,"speaker_id":1,"start_time":1067.84,"speaker_name":"Baylee Gunnell"},{"text":"So you''re good?","index":352,"end_time":1072.08,"speaker_id":1,"start_time":1071.04,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":353,"end_time":1073.12,"speaker_id":1,"start_time":1072.56,"speaker_name":"Baylee Gunnell"},{"text":"So at normal speed.","index":354,"end_time":1075.6,"speaker_id":2,"start_time":1074.08,"speaker_name":"Gab"},{"text":"Yeah.","index":355,"end_time":1076.4,"speaker_id":1,"start_time":1075.92,"speaker_name":"Baylee Gunnell"},{"text":"Oh, awesome.","index":356,"end_time":1078.56,"speaker_id":1,"start_time":1077.36,"speaker_name":"Baylee Gunnell"},{"text":"Start at the beginning.","index":357,"end_time":1079.64,"speaker_id":1,"start_time":1078.72,"speaker_name":"Baylee Gunnell"},{"text":"One more time.","index":358,"end_time":1080.32,"speaker_id":1,"start_time":1079.64,"speaker_name":"Baylee Gunnell"},{"text":"Watch.","index":359,"end_time":1081.2,"speaker_id":0,"start_time":1080.8,"speaker_name":"Tim"},{"text":"That''s almost as.","index":360,"end_time":1089.73,"speaker_id":0,"start_time":1088.57,"speaker_name":"Tim"},{"text":"That''s almost as good as being called handsome by some.","index":361,"end_time":1092.81,"speaker_id":0,"start_time":1089.73,"speaker_name":"Tim"},{"text":"Almost as Good.","index":362,"end_time":1095.77,"speaker_id":1,"start_time":1094.65,"speaker_name":"Baylee Gunnell"},{"text":"Quite.","index":363,"end_time":1096.33,"speaker_id":1,"start_time":1095.93,"speaker_name":"Baylee Gunnell"},{"text":"Not quite the same.","index":364,"end_time":1097.29,"speaker_id":1,"start_time":1096.33,"speaker_name":"Baylee Gunnell"},{"text":"Okay then that.","index":365,"end_time":1101.61,"speaker_id":1,"start_time":1100.17,"speaker_name":"Baylee Gunnell"},{"text":"That should be everything.","index":366,"end_time":1103.37,"speaker_id":1,"start_time":1102.25,"speaker_name":"Baylee Gunnell"},{"text":"Thank you.","index":367,"end_time":1105.77,"speaker_id":1,"start_time":1105.13,"speaker_name":"Baylee Gunnell"},{"text":"We.","index":368,"end_time":1106.25,"speaker_id":1,"start_time":1105.93,"speaker_name":"Baylee Gunnell"},{"text":"We also just heard back that the updated contract was signed.","index":369,"end_time":1110.01,"speaker_id":1,"start_time":1106.25,"speaker_name":"Baylee Gunnell"},{"text":"So that is a huge win.","index":370,"end_time":1111.85,"speaker_id":1,"start_time":1110.41,"speaker_name":"Baylee Gunnell"},{"text":"Thanks for working with your team on that.","index":371,"end_time":1114.34,"speaker_id":1,"start_time":1112.58,"speaker_name":"Baylee Gunnell"},{"text":"We''re excited to, to keep doing a lot of stuff this next year.","index":372,"end_time":1118.5,"speaker_id":1,"start_time":1114.34,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, absolutely.","index":373,"end_time":1120.34,"speaker_id":2,"start_time":1118.98,"speaker_name":"Gab"},{"text":"I was shocked at how quickly it went.","index":374,"end_time":1124.26,"speaker_id":2,"start_time":1120.98,"speaker_name":"Gab"},{"text":"So huge win for us.","index":375,"end_time":1127.18,"speaker_id":2,"start_time":1124.74,"speaker_name":"Gab"},{"text":"It''s not even the second week of November.","index":376,"end_time":1129.06,"speaker_id":2,"start_time":1127.18,"speaker_name":"Gab"},{"text":"That is a win in my book.","index":377,"end_time":1131.06,"speaker_id":2,"start_time":1129.06,"speaker_name":"Gab"},{"text":"Just to touch on it because I mentioned it to Christina just like in our project management system.","index":378,"end_time":1139.02,"speaker_id":2,"start_time":1133.38,"speaker_name":"Gab"},{"text":"But we''re working on a campaign right now for.","index":379,"end_time":1143.3,"speaker_id":2,"start_time":1139.02,"speaker_name":"Gab"},{"text":"To kind of position ourselves early in front of the financial lending crowd.","index":380,"end_time":1148.98,"speaker_id":2,"start_time":1143.62,"speaker_name":"Gab"},{"text":"Banks, mortgage, you know, that kind of thing.","index":381,"end_time":1151.06,"speaker_id":2,"start_time":1148.98,"speaker_name":"Gab"},{"text":"Because HR 2808 is coming which is like pretty much the end of a sale of credit triggers when it comes to people trying to qualify for a mortgage.","index":382,"end_time":1164.02,"speaker_id":2,"start_time":1152.5,"speaker_name":"Gab"},{"text":"I don''t know if I explained that correctly, but it''s in that vein and I submitted all the detail to Bailey and team to help us just with some paid visuals and that''s kind of where Christina comes in because I really want her to kind of own like what these look like copy wise and visually and then also working with the mid team to set up the campaigns in LinkedIn and just be able to, you know, review them and then optimize as we go.","index":383,"end_time":1194.03,"speaker_id":2,"start_time":1164.66,"speaker_name":"Gab"},{"text":"So more on that to come.","index":384,"end_time":1197.73,"speaker_id":2,"start_time":1196.61,"speaker_name":"Gab"},{"text":"But Christina, I did submit the project to mid, so I''m thinking maybe next Friday we''ll have, we''ll have some things to talk about as it pertains to that.","index":385,"end_time":1210.29,"speaker_id":2,"start_time":1197.97,"speaker_name":"Gab"},{"text":"Yeah, love it.","index":386,"end_time":1212.77,"speaker_id":1,"start_time":1211.81,"speaker_name":"Baylee Gunnell"},{"text":"Love that you''re using that too.","index":387,"end_time":1214.29,"speaker_id":1,"start_time":1212.77,"speaker_name":"Baylee Gunnell"},{"text":"Is there anything else too?","index":388,"end_time":1217.53,"speaker_id":1,"start_time":1216.05,"speaker_name":"Baylee Gunnell"},{"text":"It sounds like Christina, you''re going to be doing quite a bit of paid stuff.","index":389,"end_time":1222.03,"speaker_id":1,"start_time":1217.53,"speaker_name":"Baylee Gunnell"},{"text":"Is there anything else we can work with you on?","index":390,"end_time":1225.15,"speaker_id":1,"start_time":1222.59,"speaker_name":"Baylee Gunnell"},{"text":"Feel like that''s the.","index":391,"end_time":1230.19,"speaker_id":2,"start_time":1228.43,"speaker_name":"Gab"},{"text":"I thought I was on mute.","index":392,"end_time":1231.55,"speaker_id":3,"start_time":1230.35,"speaker_name":"Christina Bila"},{"text":"I think that''s all to be honest.","index":393,"end_time":1233.79,"speaker_id":3,"start_time":1231.79,"speaker_name":"Christina Bila"},{"text":"But Gavin, Tim, we can talk later to see anything else but I feel like that''s the top one right now.","index":394,"end_time":1241.23,"speaker_id":3,"start_time":1234.19,"speaker_name":"Christina Bila"},{"text":"Could you send Christina like a deck or something about our relationship or what you guys do in all the services.","index":395,"end_time":1248.75,"speaker_id":0,"start_time":1242.03,"speaker_name":"Tim"},{"text":"Maybe that will help Christina get her juices flowing about how you might be able to.","index":396,"end_time":1253.42,"speaker_id":0,"start_time":1248.99,"speaker_name":"Tim"},{"text":"Yeah, yeah.","index":397,"end_time":1255.7,"speaker_id":1,"start_time":1253.9,"speaker_name":"Baylee Gunnell"},{"text":"If you actually, if you want to stay on just a few minutes, we can go through that quick gab.","index":398,"end_time":1259.46,"speaker_id":1,"start_time":1255.7,"speaker_name":"Baylee Gunnell"},{"text":"Tim, you''re welcome to stay on or if you got other stuff to do.","index":399,"end_time":1264.14,"speaker_id":1,"start_time":1259.46,"speaker_name":"Baylee Gunnell"},{"text":"Okay, I have, I do have to go but I''ve got one more story.","index":400,"end_time":1267.42,"speaker_id":0,"start_time":1264.14,"speaker_name":"Tim"},{"text":"Bailey, my daughter just went to like a couple weeks ago, went to Park City, Utah and she''s like I''m in love with this place.","index":401,"end_time":1274.98,"speaker_id":0,"start_time":1267.5,"speaker_name":"Tim"},{"text":"This is the greatest place ever.","index":402,"end_time":1276.78,"speaker_id":0,"start_time":1274.98,"speaker_name":"Tim"},{"text":"Tell her to move out here and we''ll become friends.","index":403,"end_time":1280.39,"speaker_id":1,"start_time":1277.67,"speaker_name":"Baylee Gunnell"},{"text":"And then you''ll have to come meet me in person and we can all.","index":404,"end_time":1284.27,"speaker_id":1,"start_time":1280.55,"speaker_name":"Baylee Gunnell"},{"text":"Go to the Thai restaurant on the main street of Park City.","index":405,"end_time":1287.19,"speaker_id":2,"start_time":1284.27,"speaker_name":"Gab"},{"text":"That''s amazing.","index":406,"end_time":1288.15,"speaker_id":2,"start_time":1287.19,"speaker_name":"Gab"},{"text":"Yes, yes.","index":407,"end_time":1290.15,"speaker_id":1,"start_time":1288.71,"speaker_name":"Baylee Gunnell"},{"text":"Enough said.","index":408,"end_time":1292.23,"speaker_id":2,"start_time":1291.51,"speaker_name":"Gab"},{"text":"Okay.","index":409,"end_time":1294.07,"speaker_id":0,"start_time":1293.589,"speaker_name":"Tim"},{"text":"So I thought the.","index":410,"end_time":1295.19,"speaker_id":2,"start_time":1294.07,"speaker_name":"Gab"},{"text":"The paid social part of this campaign we''re working on would be a good, like, intro for Christina for working with the team.","index":411,"end_time":1302.39,"speaker_id":2,"start_time":1295.27,"speaker_name":"Gab"},{"text":"Well, she always works with me and Tim, but I mean, like, working with Bailey and the MID team and then, yeah, we''ll definitely kind of go back to the drawing board, just Christina, Tim and I, and look through kind of what else we could do next year in particular as well.","index":412,"end_time":1319.41,"speaker_id":2,"start_time":1304.05,"speaker_name":"Gab"},{"text":"But yeah, I''m excited.","index":413,"end_time":1321.81,"speaker_id":2,"start_time":1320.69,"speaker_name":"Gab"},{"text":"Yeah.","index":414,"end_time":1322.93,"speaker_id":1,"start_time":1322.45,"speaker_name":"Baylee Gunnell"},{"text":"Okay, so more points.","index":415,"end_time":1324.85,"speaker_id":0,"start_time":1323.25,"speaker_name":"Tim"},{"text":"So before I go, Bailey, you''ll.","index":416,"end_time":1327.41,"speaker_id":0,"start_time":1325.17,"speaker_name":"Tim"},{"text":"You''ll let me know when I can.","index":417,"end_time":1328.77,"speaker_id":0,"start_time":1327.41,"speaker_name":"Tim"},{"text":"It''s okay to make that connected decisions of PDF and I can send it to the guests?","index":418,"end_time":1334.56,"speaker_id":0,"start_time":1329.09,"speaker_name":"Tim"},{"text":"Yep.","index":419,"end_time":1335.08,"speaker_id":1,"start_time":1334.64,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, I''ll follow up today with that.","index":420,"end_time":1336.64,"speaker_id":1,"start_time":1335.08,"speaker_name":"Baylee Gunnell"},{"text":"All right.","index":421,"end_time":1338.04,"speaker_id":0,"start_time":1337.6,"speaker_name":"Tim"},{"text":"Bye, guys.","index":422,"end_time":1338.64,"speaker_id":0,"start_time":1338.04,"speaker_name":"Tim"},{"text":"Bye.","index":423,"end_time":1339.28,"speaker_id":2,"start_time":1338.8,"speaker_name":"Gab"},{"text":"Bye.","index":424,"end_time":1339.92,"speaker_id":3,"start_time":1339.44,"speaker_name":"Christina Bila"},{"text":"Bye.","index":425,"end_time":1340.88,"speaker_id":0,"start_time":1340.4,"speaker_name":"Tim"},{"text":"Okay, let''s just chat a little bit about what we do.","index":426,"end_time":1349.68,"speaker_id":1,"start_time":1345.36,"speaker_name":"Baylee Gunnell"},{"text":"So we are marketers in demand.","index":427,"end_time":1357.76,"speaker_id":1,"start_time":1354.64,"speaker_name":"Baylee Gunnell"},{"text":"We''re a collection of agencies, and we help with, like, full.","index":428,"end_time":1363.69,"speaker_id":1,"start_time":1358.41,"speaker_name":"Baylee Gunnell"},{"text":"Pretty much anything you could imagine.","index":429,"end_time":1366.25,"speaker_id":1,"start_time":1364.33,"speaker_name":"Baylee Gunnell"},{"text":"When it comes to marketing, I feel like where we fit in really well with VARISC is in this writing section and video editing and animation.","index":430,"end_time":1378.57,"speaker_id":1,"start_time":1366.33,"speaker_name":"Baylee Gunnell"},{"text":"That''s where historically a lot of the work has been that we help out with.","index":431,"end_time":1382.89,"speaker_id":1,"start_time":1378.89,"speaker_name":"Baylee Gunnell"},{"text":"But if there''s other stuff that you do need help with, we do also a ton of design work.","index":432,"end_time":1390.17,"speaker_id":1,"start_time":1383.29,"speaker_name":"Baylee Gunnell"},{"text":"Like, that kind of fits into, I feel like this branding bucket a little bit.","index":433,"end_time":1393.85,"speaker_id":1,"start_time":1390.17,"speaker_name":"Baylee Gunnell"},{"text":"But we do a lot of, like, analytics, advertising, things like that.","index":434,"end_time":1399.37,"speaker_id":1,"start_time":1395.13,"speaker_name":"Baylee Gunnell"},{"text":"It sounds like we might just maybe work a bit behind the scenes, helping create the ads, giving some recommendations on setting things up.","index":435,"end_time":1407.69,"speaker_id":1,"start_time":1399.37,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":436,"end_time":1409.69,"speaker_id":1,"start_time":1409.21,"speaker_name":"Baylee Gunnell"},{"text":"Is there anything you''d maybe add to that gab with just like, some of the stuff we''ve helped out with?","index":437,"end_time":1414.65,"speaker_id":1,"start_time":1410.25,"speaker_name":"Baylee Gunnell"},{"text":"Just speaking to the paid aspect, because it was kind of my first time seeing a recommendation from y'' all about what we could do for paid for, specifically the ebook.","index":438,"end_time":1426.39,"speaker_id":2,"start_time":1417.75,"speaker_name":"Gab"},{"text":"I think that''s like, just a great brief that Christina can take back to our team and kind of get our.","index":439,"end_time":1436.03,"speaker_id":2,"start_time":1428.31,"speaker_name":"Gab"},{"text":"Not just like our buy in, but also, like.","index":440,"end_time":1438.03,"speaker_id":2,"start_time":1436.03,"speaker_name":"Gab"},{"text":"Yes, and we could also be doing this as well on top of that.","index":441,"end_time":1441.43,"speaker_id":2,"start_time":1438.03,"speaker_name":"Gab"},{"text":"Um, but I think you captured just the.","index":442,"end_time":1444.96,"speaker_id":2,"start_time":1442,"speaker_name":"Gab"},{"text":"The status of our relationship as it is now, like, very well.","index":443,"end_time":1448.32,"speaker_id":2,"start_time":1444.96,"speaker_name":"Gab"},{"text":"Um, I also know that, like, Becky has been working with mid on a couple things for events as well, so really, the MIT team touches everyone on our team.","index":444,"end_time":1462.16,"speaker_id":2,"start_time":1448.72,"speaker_name":"Gab"},{"text":"Yeah, we have a lot of stuff.","index":445,"end_time":1467.04,"speaker_id":1,"start_time":1462.72,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":446,"end_time":1467.85,"speaker_id":1,"start_time":1467.53,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":447,"end_time":1469.65,"speaker_id":1,"start_time":1469.21,"speaker_name":"Baylee Gunnell"},{"text":"And if you''re not sure, just reach out and.","index":448,"end_time":1472.17,"speaker_id":1,"start_time":1469.65,"speaker_name":"Baylee Gunnell"},{"text":"And we can figure something out.","index":449,"end_time":1474.73,"speaker_id":1,"start_time":1472.25,"speaker_name":"Baylee Gunnell"},{"text":"And then we''re a collection of agencies, so Marketers In Demand is the parent company.","index":450,"end_time":1480.57,"speaker_id":1,"start_time":1475.29,"speaker_name":"Baylee Gunnell"},{"text":"And, like, our growth strategy has been to acquire other agencies so that we can tap into their expertise.","index":451,"end_time":1488.97,"speaker_id":1,"start_time":1481.21,"speaker_name":"Baylee Gunnell"},{"text":"So, like, Gab started off working with us as Motion.","index":452,"end_time":1493.7,"speaker_id":1,"start_time":1489.13,"speaker_name":"Baylee Gunnell"},{"text":"That was, like, our first agency, and that''s a podcast production agency.","index":453,"end_time":1497.7,"speaker_id":1,"start_time":1493.7,"speaker_name":"Baylee Gunnell"},{"text":"And then we started with New North.","index":454,"end_time":1501.26,"speaker_id":1,"start_time":1499.3,"speaker_name":"Baylee Gunnell"},{"text":"So that''s where we really expanded a lot of things.","index":455,"end_time":1503.38,"speaker_id":1,"start_time":1501.26,"speaker_name":"Baylee Gunnell"},{"text":"And now we also have Ideometry and spoke.","index":456,"end_time":1507.62,"speaker_id":1,"start_time":1503.62,"speaker_name":"Baylee Gunnell"},{"text":"I. I explained this because sometimes people get confused about, like, why are you marketers in demand when they started with us as Motion or New North?","index":457,"end_time":1518.02,"speaker_id":1,"start_time":1508.899,"speaker_name":"Baylee Gunnell"},{"text":"So if you see those names around, that''s where it comes from.","index":458,"end_time":1520.75,"speaker_id":1,"start_time":1518.02,"speaker_name":"Baylee Gunnell"},{"text":"Sounds good.","index":459,"end_time":1522.03,"speaker_id":3,"start_time":1521.23,"speaker_name":"Christina Bila"},{"text":"Yeah, but.","index":460,"end_time":1524.27,"speaker_id":1,"start_time":1522.51,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, that''s the main gist of it, but super excited to be working with you and.","index":461,"end_time":1529.47,"speaker_id":1,"start_time":1524.27,"speaker_name":"Baylee Gunnell"},{"text":"And get to know you better and just work on other projects.","index":462,"end_time":1533.07,"speaker_id":1,"start_time":1529.71,"speaker_name":"Baylee Gunnell"},{"text":"I''m excited as well.","index":463,"end_time":1534.91,"speaker_id":3,"start_time":1533.71,"speaker_name":"Christina Bila"},{"text":"So when Gab was like, we should do more paid strategy, I was like, yes, let''s do it.","index":464,"end_time":1539.63,"speaker_id":3,"start_time":1534.91,"speaker_name":"Christina Bila"},{"text":"So I''m excited.","index":465,"end_time":1540.59,"speaker_id":3,"start_time":1539.63,"speaker_name":"Christina Bila"},{"text":"I think it''s good for us.","index":466,"end_time":1542.43,"speaker_id":1,"start_time":1540.59,"speaker_name":"Baylee Gunnell"},{"text":"So I''m looking forward to it.","index":467,"end_time":1543.95,"speaker_id":3,"start_time":1542.51,"speaker_name":"Christina Bila"},{"text":"And Christina''s kind of, like, coming into this growth marketing role More so in 2026.","index":468,"end_time":1549.47,"speaker_id":2,"start_time":1544.27,"speaker_name":"Gab"},{"text":"So I know, Christina, you''re probably already thinking of a strategy for next year.","index":469,"end_time":1556.28,"speaker_id":2,"start_time":1551.32,"speaker_name":"Gab"},{"text":"Like, it is prime time for that.","index":470,"end_time":1557.64,"speaker_id":2,"start_time":1556.28,"speaker_name":"Gab"},{"text":"So maybe another thing is just kind of collaborating with the MID team and particularly Ideometry, because I saw that they are kind of like the growth agency within MID for, like, any additional recommendations to our strategy, because I saw strategy was a pillar that MIT can tap into, so maybe we can try that out as well.","index":471,"end_time":1580.35,"speaker_id":2,"start_time":1558.92,"speaker_name":"Gab"},{"text":"I think so.","index":472,"end_time":1582.19,"speaker_id":1,"start_time":1581.39,"speaker_name":"Baylee Gunnell"},{"text":"I guess, side note for you and I, we need a session on that, because I have some things gathered, but just helping me with the full picture because I feel like I started right in the middle of a lot of different things happening, so.","index":473,"end_time":1598.27,"speaker_id":3,"start_time":1584.43,"speaker_name":"Christina Bila"},{"text":"Yeah.","index":474,"end_time":1598.59,"speaker_id":1,"start_time":1598.27,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, you did.","index":475,"end_time":1599.31,"speaker_id":2,"start_time":1598.59,"speaker_name":"Gab"},{"text":"Yeah, you did.","index":476,"end_time":1600.27,"speaker_id":2,"start_time":1599.39,"speaker_name":"Gab"},{"text":"So we can.","index":477,"end_time":1602.19,"speaker_id":2,"start_time":1600.91,"speaker_name":"Gab"},{"text":"We''ll connect on a.","index":478,"end_time":1603.27,"speaker_id":2,"start_time":1602.19,"speaker_name":"Gab"},{"text":"On another call maybe next week, just.","index":479,"end_time":1605.5,"speaker_id":2,"start_time":1603.27,"speaker_name":"Gab"},{"text":"Go through what we have now.","index":480,"end_time":1606.74,"speaker_id":1,"start_time":1605.5,"speaker_name":"Baylee Gunnell"},{"text":"Maybe how MID can help flesh it out even further if we need help.","index":481,"end_time":1610.98,"speaker_id":2,"start_time":1606.82,"speaker_name":"Gab"},{"text":"But, yeah, I''m looking forward to that.","index":482,"end_time":1614.1,"speaker_id":2,"start_time":1612.34,"speaker_name":"Gab"},{"text":"Yeah.","index":483,"end_time":1614.98,"speaker_id":1,"start_time":1614.5,"speaker_name":"Baylee Gunnell"},{"text":"One thing, with the paid, it might be beneficial if we had, like, almost like a kickoff call, and we can talk bigger strategy, like, what are you trying to accomplish for the whole year?","index":484,"end_time":1628.74,"speaker_id":1,"start_time":1615.3,"speaker_name":"Baylee Gunnell"},{"text":"What do you have coming up, things like that, and then we can help put together some documentation for you and your team to take a look at.","index":485,"end_time":1636.41,"speaker_id":1,"start_time":1629.06,"speaker_name":"Baylee Gunnell"},{"text":"So rather than just focusing on a single strategy, like, here''s roughly our plan for the next quarter or the year, whatever that ends up being, for sure.","index":486,"end_time":1645.57,"speaker_id":1,"start_time":1636.41,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":487,"end_time":1646.21,"speaker_id":1,"start_time":1645.73,"speaker_name":"Baylee Gunnell"},{"text":"We are still kind of working on individual parts as a team and then coming together to put the parts together for the broader strategy.","index":488,"end_time":1655.33,"speaker_id":2,"start_time":1646.21,"speaker_name":"Gab"},{"text":"So when I know.","index":489,"end_time":1657.65,"speaker_id":2,"start_time":1656.69,"speaker_name":"Gab"},{"text":"Yes.","index":490,"end_time":1659.65,"speaker_id":1,"start_time":1659.25,"speaker_name":"Baylee Gunnell"},{"text":"No, sounds great.","index":491,"end_time":1661.49,"speaker_id":1,"start_time":1659.73,"speaker_name":"Baylee Gunnell"},{"text":"Perfect.","index":492,"end_time":1663.17,"speaker_id":1,"start_time":1662.61,"speaker_name":"Baylee Gunnell"},{"text":"Okay, awesome.","index":493,"end_time":1666.13,"speaker_id":1,"start_time":1665.09,"speaker_name":"Baylee Gunnell"},{"text":"Well, thank you for chatting, and we''ll talk again here soon.","index":494,"end_time":1669.81,"speaker_id":1,"start_time":1666.13,"speaker_name":"Baylee Gunnell"},{"text":"All right.","index":495,"end_time":1670.85,"speaker_id":1,"start_time":1670.21,"speaker_name":"Baylee Gunnell"},{"text":"Thank you.","index":496,"end_time":1671.45,"speaker_id":3,"start_time":1671.01,"speaker_name":"Christina Bila"},{"text":"It was nice meeting you.","index":497,"end_time":1672.61,"speaker_id":3,"start_time":1671.45,"speaker_name":"Christina Bila"},{"text":"We''ll see you.","index":498,"end_time":1674.209,"speaker_id":1,"start_time":1673.41,"speaker_name":"Baylee Gunnell"},{"text":"Bye.","index":499,"end_time":1675.17,"speaker_id":2,"start_time":1674.77,"speaker_name":"Gab"},{"text":"Bye.","index":500,"end_time